class Solution:
    def minIncrease(self, n, edges, cost):
        from collections import defaultdict
        children = defaultdict(list)
        adj = defaultdict(list)
        for u, v in edges:
            adj[u].append(v)
            adj[v].append(u)
        # root at 0, build children via BFS to avoid recursion-depth issues
        from collections import deque
        parent = [-1] * n
        order = []
        seen = [False] * n
        dq = deque([0]); seen[0] = True
        while dq:
            u = dq.popleft(); order.append(u)
            for w in adj[u]:
                if not seen[w]:
                    seen[w] = True; parent[w] = u; children[u].append(w); dq.append(w)
        # process in reverse BFS order (leaves first)
        path = [0] * n  # balanced path sum from node down to leaves
        count = 0
        for u in reversed(order):
            ch = children[u]
            if not ch:
                path[u] = cost[u]
            else:
                mx = max(path[c] for c in ch)
                for c in ch:
                    if path[c] < mx:
                        count += 1
                path[u] = cost[u] + mx
        return count

