                    seen[w] = True; parent[w] = u; dq.append(w)
        path = [0] * n
        count = 0
        children = [[] for _ in range(n)]
        for v in range(n):
            if parent[v] != -1:
                children[parent[v]].append(v)
        for u in reversed(order):
            ch = children[u]
            if not ch:
                path[u] = cost[u]
