var minIncrease = function(n, edges, cost) {
    const adj = Array.from({length: n}, () => []);
    for (const [u, v] of edges) { adj[u].push(v); adj[v].push(u); }
    const parent = new Array(n).fill(-1);
    const order = [];
    const seen = new Array(n).fill(false);
    const queue = [0]; seen[0] = true;
    let qh = 0;
    while (qh < queue.length) {
        const u = queue[qh++]; order.push(u);
        for (const w of adj[u]) {
            if (!seen[w]) { seen[w] = true; parent[w] = u; queue.push(w); }
        }
    }
    const children = Array.from({length: n}, () => []);
    for (let v = 0; v < n; v++) if (parent[v] !== -1) children[parent[v]].push(v);
    const path = new Array(n).fill(0);
    let count = 0;
    for (let i = order.length - 1; i >= 0; i--) {
        const u = order[i];
        const ch = children[u];
        if (ch.length === 0) {
            path[u] = cost[u];
        } else {
            let mx = 0;
            for (const c of ch) if (path[c] > mx) mx = path[c];
            for (const c of ch) if (path[c] < mx) count++;
            path[u] = cost[u] + mx;
        }
    }
    return count;
};
